import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
function homePage(){
    const page = (
        <div id = "main">
            <div id = "signin">
            <br></br>
            <h2 id = "a">Login With Your Email Address</h2>
            <input type = "text"  id = "username" placeholder = "Username"></input>
            <br></br>
            <input type = "text" id = "password" placeholder = "Password"></input>
                <br></br>
                <br></br>
                <input id = "login" type="submit" value="Submit" onClick= {Login}/>
                <br></br>
            <h2 id = "b">Sign Up With Your Email Address</h2>
            <input type = "text" id = "emailaddress" placeholder = "Email Address"></input>
            <br></br>
            <input type = "text" id = "pass" placeholder = "Password"></input>
                <br></br>
                <br></br>
                <input id = "signup" type="submit" value="Submit" onClick= {signUp}/>
            </div>
        </div>
    );
    ReactDOM.render(page, document.getElementById('root'))
    function Login(){
        var username = document.getElementById('username').value
        var password = document.getElementById('password').value
        var xhr = new XMLHttpRequest();  
        xhr.open("POST", "http://localhost:8000/");
        xhr.setRequestHeader("Content-Type", "application/json;charset=UTF-8");
        xhr.onreadystatechange = function(){
            if (this.readyState === XMLHttpRequest.DONE && this.status === 200){
                console.log("sent")
                response()
            }
        }
        xhr.send(JSON.stringify({ "user": username, "pass": password, "type": "findUser" }));
    }
    function response(){
        function sub() {
            let url = 'http://localhost:8000/files/temp.json';
            fetch(url)
            .then(res => res.json())
            .then((out) => {
                function check(){
                    if (JSON.stringify(out) === `{"message":null}`){
                        console.log(false)
                    } else {
                        console.log(true)
                        //move to homepage
                        const homepage = (
                            <div id = "gfyu">
                                <img alt = "Loading..." class = "center" height = "300" width = "300" src = "https://i.pinimg.com/originals/3f/2c/97/3f2c979b214d06e9caab8ba8326864f3.gif"></img>
                                <br></br>
                                <h2 id = "loadingtext">Loading...</h2>
                            </div>
                        )
                        ReactDOM.render(homepage, document.getElementById('root'))
                        if (out.message.book1 === "none" && out.message.book2 === "none"&& out.message.book4 === "none"&& out.message.book5 === "none" && out.message.id === "makeone"){
                            console.log("newuser")
                            function af(){
                                const createprofile = (
                                    <div id = "fghdsj">
                                        <br></br>
                                        <h3 id = "gg">Let's get started!</h3>
                                        <br></br>
                                        <h3 id = "ugfj">Choose A Nickname (This is your public name)</h3>
                                        <br></br>
                                        <input type = "text" id = "nickname" placeholder = "Nickname"></input>
                                        <br></br>
                                        <h3 id = "ugfj">Choose Your Favorite Top 5 Favorite Books (This will be part of your profile)</h3>
                                        <br></br>
                                        <input type = "text" id = "book1" placeholder = "Book #1"></input>
                                        <br></br>
                                        <input type = "text" id = "book2" placeholder = "Book #2"></input>
                                        <br></br>
                                        <input type = "text" id = "book3" placeholder = "Book #3"></input>
                                        <br></br>
                                        <input type = "text" id = "book4" placeholder = "Book #4"></input>
                                        <br></br>
                                        <input type = "text" id = "book5" placeholder = "Book #5"></input>
                                    </div>
                                )
                                ReactDOM.render(createprofile, document.getElementById('root'))
                            }
                            setTimeout(af, 2000)
                        }
                    }
                }
                check()
            })
            .catch(err => { throw err });
        }
        setTimeout(sub, 1000)
    }
    function signUp(){
        var emailaddress = document.getElementById('emailaddress').value
        var pass = document.getElementById('pass').value 
        var xhr = new XMLHttpRequest();
        xhr.open("POST", "http://localhost:8000/")
        xhr.setRequestHeader("Content-Type", "application/json;charset=UTF-8");
        xhr.onreadystatechange = function(){
            if (this.readyState === XMLHttpRequest.DONE && this.status === 200){
                console.log("sent")
                window.location.reload()
            }
        }
        xhr.send(JSON.stringify({ "user": emailaddress, "pass": pass, "type": "createUser" }));

    }
}
homePage()
export default homePage
